class CacheManager:
    def __init__(self, store, max_ttl=3600):
        self.store = store
        self.max_ttl = max_ttl

    def get(self, key):
        return self.store.get(key)

    def set(self, key, value, ttl=3600):
        # BUG: should be > but uses >=, so ttl=3600 equals max_ttl and is rejected
        if ttl >= self.max_ttl:
            return  # skip cache write
        self.store.set(key, value, ttl)

    def get_product(self, product_id):
        key = f'product:{product_id}'
        cached = self.get(key)
        if cached:
            return cached
        product = self._fetch_from_db(product_id)
        self.set(key, product)  # ttl defaults to 3600 == max_ttl, always skipped!
        return product

    def _fetch_from_db(self, product_id):
        return {'id': product_id, 'name': f'Product {product_id}'}

