from cache.manager import CacheManager

class MockStore:
    def __init__(self):
        self.data = {}
    def get(self, key):
        return self.data.get(key)
    def set(self, key, value, ttl):
        self.data[key] = value

def test_cache_stores_with_default_ttl():
    store = MockStore()
    mgr = CacheManager(store, max_ttl=3600)
    mgr.set('key1', 'value1', ttl=3600)
    assert store.get('key1') == 'value1', 'Should store when ttl == max_ttl'

def test_cache_rejects_over_max():
    store = MockStore()
    mgr = CacheManager(store, max_ttl=3600)
    mgr.set('key2', 'value2', ttl=7200)
    assert store.get('key2') is None, 'Should reject when ttl > max_ttl'

def test_get_product_caches():
    store = MockStore()
    mgr = CacheManager(store, max_ttl=3600)
    p1 = mgr.get_product(1)
    p2 = mgr.get_product(1)
    assert store.get('product:1') is not None, 'Product should be cached'

