import yaml

def validate_config(config_path):
    with open(config_path) as f:
        config = yaml.safe_load(f)
    required = ['service', 'version', 'replicas']
    for key in required:
        if key not in config:
            raise ValueError(f'Missing required key: {key}')
    return config
